function ph27Shape(lot){
  const n=Number(lot.id);
  if(n===3)return box(11.2,25.3,14.2,8.7);
  if(n===2)return box(11.2,34.0,14.2,8.7);
  if(n===1)return poly([[11.2,42.7],[25.4,42.7],[25.4,52.2],[12.9,52.2],[11.2,49.7]]);
  if(n>=4&&n<=17){const x=25.4+(n-4)*4.72;return box(x,25.3,4.72,26.9)}
  return null;
}





