function genericPlatShape(lot,index,total){
  const cols=Math.ceil(Math.sqrt(total));
  const rows=Math.ceil(total/cols);
  const padX=13,padY=18,W=74,H=62,gap=.8;
  const c=index%cols,r=Math.floor(index/cols);
  return box(padX+c*(W/cols),padY+r*(H/rows),(W/cols)-gap,(H/rows)-gap);
}
function getLotShape(s,lot,index){
  if(s.id==='ph27')return ph27Shape(lot);
  if(s.id==='lasgaviotas')return lasGaviotasShape(lot);
  if(s.id==='phase31')return phase31Shape(lot);
  if(s.id==='uri4')return uri4Shape(lot);
  if(s.id==='lamulada2')return lamulada2Shape(lot);
  if(s.id==='milanos4')return milanos4Shape(lot);
  if(s.id==='milanos3')return milanos3Shape(lot);
  return genericPlatShape(lot,index,s.lots.length);
}
function renderPlatOverlay(s){
  const svg=document.getElementById('plat-svg');
  const missing=document.getElementById('plat-missing');
  const wrap=document.getElementById('plat-wrap');
  const note=document.getElementById('plat-note');
  svg.innerHTML='';
  platStatusFilter='all';
  document.querySelectorAll('.plat-filter').forEach((b,i)=>b.classList.toggle('on',i===0));
  if(AERIAL_ONLY_IDS.has(s.id)){
    wrap.style.display='none';
    missing.style.display='block';
    return;
  }
  wrap.style.display='block';
  missing.style.display='none';
  const useUnifiedSvg=s.id==='lasgaviotas';
  // Keep subdivision-specific visual tuning scoped to the current plat only.
  wrap.className = wrap.className
    .split(/\s+/)
    .filter(c => c && !c.startsWith('plat-id-'))
    .join(' ');
  wrap.classList.add('plat-id-'+s.id);
  wrap.classList.toggle('svg-canvas',useUnifiedSvg);
  if(s.id==='phase31'){
    wrap.style.setProperty('--plat-aspect','2048/1061');
  }else if(s.id==='uri4'){
    wrap.style.setProperty('--plat-aspect','1366/1332');
  }else if(s.id==='lamulada2'){
    wrap.style.setProperty('--plat-aspect','2048/1035');
  }else if(s.id==='milanos4'){
    wrap.style.setProperty('--plat-aspect','1604/868');
  }else if(s.id==='milanos3'){
    wrap.style.setProperty('--plat-aspect','2031/1586');
  }else{
    wrap.style.removeProperty('--plat-aspect');
  }
  let overlayRoot=svg;
  if(useUnifiedSvg){
    const lgZoom = s.id==='lasgaviotas' ? '300 180 1093 820' : '0 0 1400 1050';
    svg.setAttribute('viewBox',lgZoom);
    svg.setAttribute('preserveAspectRatio','xMidYMid meet');
    const img=document.createElementNS('http://www.w3.org/2000/svg','image');
    img.setAttribute('x','0');img.setAttribute('y','0');img.setAttribute('width','1400');img.setAttribute('height','1050');
    img.setAttribute('preserveAspectRatio','none');
    img.setAttributeNS('http://www.w3.org/1999/xlink','href',s.image);
    img.setAttribute('href',s.image);
    svg.appendChild(img);
    overlayRoot=document.createElementNS('http://www.w3.org/2000/svg','g');
    overlayRoot.setAttribute('transform','matrix(1 0 0 0.9645 0 -1.25)');
    svg.appendChild(overlayRoot);
  }else{
    wrap.classList.remove('svg-canvas');
    if(s.id==='phase31'){
      svg.setAttribute('viewBox','0 0 2048 1061');
      svg.setAttribute('preserveAspectRatio','none');
    }else if(s.id==='uri4'){
      svg.setAttribute('viewBox','0 0 1366 1332');
      svg.setAttribute('preserveAspectRatio','none');
    }else if(s.id==='lamulada2'){
      svg.setAttribute('viewBox','0 0 2048 1035');
      svg.setAttribute('preserveAspectRatio','none');
    }else if(s.id==='milanos4'){
      svg.setAttribute('viewBox','0 0 1604 868');
      svg.setAttribute('preserveAspectRatio','none');
    }else if(s.id==='milanos3'){
      svg.setAttribute('viewBox','0 0 2031 1586');
      svg.setAttribute('preserveAspectRatio','none');
    }else{
      svg.setAttribute('viewBox','0 0 100 100');
      svg.setAttribute('preserveAspectRatio','none');
    }
  }
  note.textContent=s.id==='ph27'||s.id==='lasgaviotas'||s.id==='phase31'||s.id==='uri4'||s.id==='lamulada2'||s.id==='milanos4'||s.id==='milanos3'?'Tap a highlighted lot on the plat for pricing and Call Now':'Tap a highlighted lot. Overlay is plat-only and can be tuned after final tracing.';
  s.lots.forEach((lot,i)=>{
    const shape=getLotShape(s,lot,i);
    if(!shape)return;
    const cls=lot.status==='pending'?'pending':lot.status==='hold'?'hold':lot.status==='sold'?'sold':'available';
    let el;
    if(shape.type==='poly'){
      el=document.createElementNS('http://www.w3.org/2000/svg','polygon');
      el.setAttribute('points',shape.points.map(p=>p.join(',')).join(' '));
    }else{
      el=document.createElementNS('http://www.w3.org/2000/svg','rect');
      el.setAttribute('x',shape.x);el.setAttribute('y',shape.y);el.setAttribute('width',shape.w);el.setAttribute('height',shape.h);
      el.setAttribute('rx',.25);
    }
    el.classList.add('plat-lot',cls);
    el.id='plat-lot-'+lot.id;
    el.dataset.status=lot.status;
    el.onclick=(ev)=>{ev.stopPropagation();openPanel(lot)};
    overlayRoot.appendChild(el);
    // Match Phase 31 behavior: these plats use clean color overlays without lot-number text inside the overlay.
    const noOverlayLabels = s.id==='phase31' || s.id==='lasgaviotas' || s.id==='ph27';
    if(!noOverlayLabels){
      const cx=shape.type==='poly'?shape.points.reduce((a,p)=>a+p[0],0)/shape.points.length:shape.x+shape.w/2;
      const cy=shape.type==='poly'?shape.points.reduce((a,p)=>a+p[1],0)/shape.points.length:shape.y+shape.h/2;
      const t=document.createElementNS('http://www.w3.org/2000/svg','text');
      t.setAttribute('x',cx);t.setAttribute('y',cy);
      t.classList.add('plat-lot-label',cls);
      t.dataset.status=lot.status;
      t.textContent='#'+lot.id;
      overlayRoot.appendChild(t);
    }
  });
}


function getMaxLotAcres(s){
  let max=0;
  (s.lots||[]).forEach(l=>{
    const raw=String(l.acres||"").replace(/[^0-9.]/g,"");
    const val=parseFloat(raw);
    if(!isNaN(val)) max=Math.max(max,val);
  });
  return max;
}
function acreBucketMatch(s,filter){
  if(!["half","midacre","tenplus"].includes(filter)) return false;
  if(s.sizeKey==="city") return false;
  if(s.sizeKey==="tenplus") return filter==="tenplus";
  const max=getMaxLotAcres(s);
  if(filter==="half") return max>0 && max<3;
  if(filter==="midacre") return max>=3 && max<10;
  if(filter==="tenplus") return max>=10;
  return false;
}


let propertyMap=null,propertyMarkers=[],propertyMapOpen=true;
function subdivisionMatchesFilters(s){
  const cityMatch=!currentCityFilter||s.city===currentCityFilter;
  const sizeMatch=!currentSizeFilter||s.sizeKey===currentSizeFilter||acreBucketMatch(s,currentSizeFilter);
  const statusMatch=!currentStatusFilter||currentStatusFilter==="all"||subdivisionStatus(s)===currentStatusFilter;
  const q=(currentSearchFilter||"").trim().toLowerCase();
  const searchText=[s.name,s.city,s.county,s.size,s.sizeKey,(s.tags||[]).join(" ")].join(" ").toLowerCase();
  const searchMatch=!q||searchText.includes(q);
  return cityMatch&&sizeMatch&&statusMatch&&searchMatch;
}
function getFilteredSubdivisions(){
  return SUBDIVISIONS.filter(subdivisionMatchesFilters).sort((a,b)=>statusRank(a)-statusRank(b)||a.name.localeCompare(b.name));
}
function togglePropertyMap(){
  propertyMapOpen=!propertyMapOpen;
  const shell=document.getElementById("location-map-shell");
  const btn=document.getElementById("map-toggle");
  if(shell) shell.classList.toggle("open",propertyMapOpen);
  if(btn) btn.textContent=propertyMapOpen ? "Hide Map View" : "Show Map View";
  if(propertyMapOpen){
    setTimeout(()=>{renderPropertyMap();propertyMap?.invalidateSize();},50);
  }
}
function renderPropertyMap(){
  const mapEl=document.getElementById("property-map");
  const listEl=document.getElementById("map-list");
  if(!mapEl||!listEl||typeof L==="undefined") return;
  if(!propertyMap){
    propertyMap=L.map(mapEl,{scrollWheelZoom:false}).setView([26.24,-98.18],9);
    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{
      maxZoom:19,
      attribution:"&copy; OpenStreetMap"
    }).addTo(propertyMap);
  }
  propertyMarkers.forEach(m=>m.remove());
  propertyMarkers=[];
  listEl.innerHTML="";
  const items=getFilteredSubdivisions().filter(s=>typeof s.lat==="number"&&typeof s.lng==="number");
  if(!items.length){
    listEl.innerHTML='<div style="padding:18px;color:var(--sage);font-size:.88rem">No mapped subdivisions match the current filters.</div>';
    return;
  }
  const bounds=[];
  items.forEach((s,idx)=>{
    const cnt=countStatus(s.lots);
    const minP=s.lots.filter(l=>l.status==="available").reduce((m,l)=>Math.min(m,l.price),Infinity);
    const marker=L.marker([s.lat,s.lng]).addTo(propertyMap);
    const popup=`<div class="map-popup-title">${s.name}</div>
      <div class="map-popup-meta">${s.city}, ${s.county} County<br>${statusLabel(s)} · ${minP<Infinity?fmtP(minP):"Call"} starting</div>
      <div class="map-popup-actions">
        <button onclick="openDetail('${s.id}')">View Lots</button>
        <a href="${s.mapUrl||('https://www.google.com/maps?q='+s.lat+','+s.lng)}" target="_blank" rel="noopener">Directions</a>
      </div>`;
    marker.bindPopup(popup);
    propertyMarkers.push(marker);
    bounds.push([s.lat,s.lng]);
    const row=document.createElement("button");
    row.className="map-list-item";
    row.type="button";
    row.innerHTML=`<span class="map-pin-num">${idx+1}</span><span><span class="map-item-name">${s.name}</span><span class="map-item-meta">${s.city} · ${s.size} · ${statusLabel(s)}</span></span>`;
    row.onclick=()=>{propertyMap.setView([s.lat,s.lng],13);marker.openPopup();};
    listEl.appendChild(row);
  });
  if(bounds.length===1){
    propertyMap.setView(bounds[0],13);
  }else{
    propertyMap.fitBounds(bounds,{padding:[28,28],maxZoom:11});
  }
}

function renderHome(){
  const grid=document.getElementById("prop-grid"),noR=document.getElementById("no-results"),cntEl=document.getElementById("filter-count");
  let shown=0,totalAvail=0;
  grid.innerHTML="";
  getFilteredSubdivisions().forEach(s=>{
    shown++;
    const cnt=countStatus(s.lots);
    totalAvail+=cnt.available;
    const minP=s.lots.filter(l=>l.status==="available").reduce((m,l)=>Math.min(m,l.price),Infinity);
    const card=document.createElement("div");
    const st=subdivisionStatus(s);
    const isSoldOut=st==="soldout";
    const isComing=st==="coming";
    card.className="prop-card"+(isSoldOut?" sold-out":"");
    card.setAttribute("role","button");
    card.setAttribute("tabindex","0");
    card.setAttribute("aria-label","View lot map and pricing for "+s.name);
    card.onclick=()=>openDetail(s.id);
    card.onkeydown=(ev)=>{if(ev.key==="Enter"||ev.key===" "){ev.preventDefault();openDetail(s.id)}};
    const availText=isSoldOut?"Sold Out":(isComing?"Coming Soon":`${cnt.available} lot${cnt.available===1?"":"s"} available`);
    const priceText=isSoldOut?"Sold Out":(minP<Infinity?fmtP(minP):"Call");
    const priceSmall=isSoldOut?"Past Community":(isComing?"More Info Coming Soon":"Starting Price");
    const ctaText=isSoldOut?"Join Interest List / Similar Lots →":(isComing?"Call for Upcoming Details →":"View Lot Map & Pricing →");
    card.innerHTML=`<div class="prop-card-img"><img src="${s.cardImage||s.image}" alt="${s.name}" loading="lazy" onerror="this.style.display='none'"><div class="prop-card-badges">${tagHTML(tagsForSubdivision(s))}</div><div class="prop-avail-badge ${isSoldOut?'soldout':''}"><div class="prop-avail-dot ${isSoldOut?'soldout':''}"></div>${availText}</div></div><div class="prop-card-body"><div class="prop-card-name">${s.name}</div><div class="prop-card-loc">📍 ${s.city}, ${s.county} County</div><div class="prop-card-meta"><span class="prop-card-size">${s.size}</span><div class="prop-card-price">${priceText}<small>${priceSmall}</small></div></div><button class="prop-card-cta" type="button">${ctaText}</button></div>`;
    grid.appendChild(card);
  });
  noR.style.display=shown===0?"block":"none";
  cntEl.textContent=shown+" subdivision"+(shown!==1?"s":"")+" shown";
  document.getElementById("hero-avail").textContent=totalAvail+"+";
  if(propertyMapOpen) renderPropertyMap();
}

function syncFilterUI(){
  document.querySelectorAll(".chip").forEach(c=>c.classList.remove("on"));
  document.querySelectorAll(".status-chip").forEach(c=>c.classList.remove("on"));
  const citySel=document.getElementById("city-filter");
  const sizeSel=document.getElementById("size-filter");
  const searchInput=document.getElementById("subdivision-search");
  if(citySel) citySel.value=currentCityFilter;
  if(sizeSel) sizeSel.value=currentSizeFilter;
  if(searchInput && searchInput.value!==currentSearchFilter) searchInput.value=currentSearchFilter;
  const statusBtn=document.getElementById("status-"+currentStatusFilter+"-btn");
  if(statusBtn) statusBtn.classList.add("on");
}
function setFilter(f,el){
  if(f==="all"){
    currentCityFilter="";
    currentSizeFilter="";
  }
  currentFilter=(currentCityFilter||currentSizeFilter||currentStatusFilter!=="all") ? "combined" : "all";
  syncFilterUI();
  renderHome();
}
function setStatusFilter(f,el){
  currentStatusFilter=f||"all";
  currentFilter=(currentCityFilter||currentSizeFilter||currentStatusFilter!=="all") ? "combined" : "all";
  syncFilterUI();
  renderHome();
}
function setFilterFromSelect(sel,type){
  if(type==="city"){
    currentCityFilter=sel.value||"";
  }else if(type==="size"){
    currentSizeFilter=sel.value||"";
  }
  currentFilter=(currentCityFilter||currentSizeFilter||currentStatusFilter!=="all") ? "combined" : "all";
  syncFilterUI();
  renderHome();
}
function setSearchFilter(v){
  currentSearchFilter=(v||"").trim();
  currentFilter=(currentCityFilter||currentSizeFilter||currentSearchFilter||currentStatusFilter!=="all") ? "combined" : "all";
  renderHome();
}
function scrollToProps(){document.getElementById("props-section").scrollIntoView({behavior:"smooth"})}

function openDetail(id){
  currentSubdiv=SUBDIVISIONS.find(s=>s.id===id);
  if(!currentSubdiv)return;
  const s=currentSubdiv;
  showPage("detail");
  const cnt=countStatus(s.lots);
  const minP=s.lots.filter(l=>l.status==="available").reduce((m,l)=>Math.min(m,l.price),Infinity);
  document.getElementById("d-labels").innerHTML=tagHTML(tagsForSubdivision(s));
  document.getElementById("d-name").textContent=s.name;
  document.getElementById("d-loc").innerHTML=`📍 <a href="${s.mapUrl||s.mapsEmbed}" target="_blank" rel="noopener" style="color:inherit;text-decoration:underline;text-underline-offset:3px">${s.address}</a>`;
  const st=subdivisionStatus(s);
  const isSoldOut=st==="soldout";
  document.getElementById("d-price").innerHTML=(isSoldOut?"Sold Out":(minP<Infinity?fmtP(minP):"Call for Price"))+"<small> "+(isSoldOut?"Past Community":"Starting Price &middot; Seller Financing")+"</small>";
  document.getElementById("d-lotcount").textContent=s.lots.length+" Total "+(s.unitLabelPlural||"Lots");
  const soldBanner=document.getElementById("soldout-banner");
  const similarBox=document.getElementById("similar-subdivisions");
  if(soldBanner){
    if(isSoldOut){
      soldBanner.style.display="block";
      soldBanner.innerHTML=`<strong>This subdivision is currently sold out.</strong> We keep this page available for reference. For similar available properties, call <a href="tel:9563833222">(956) 383-3222</a> or send an interest request below.`;
    }else{ soldBanner.style.display="none"; soldBanner.innerHTML=""; }
  }
  if(similarBox){
    if(isSoldOut){
      const similar=SUBDIVISIONS.filter(x=>x.id!==s.id && subdivisionStatus(x)==="available" && (x.city===s.city || x.sizeKey===s.sizeKey)).slice(0,3);
      if(similar.length){
        similarBox.style.display="block";
        similarBox.innerHTML=`<div class="similar-box-title">Similar available subdivisions</div><div class="similar-links">${similar.map(x=>`<button type="button" onclick="openDetail('${x.id}')">${x.name}</button>`).join("")}</div>`;
      }else{ similarBox.style.display="none"; similarBox.innerHTML=""; }
    }else{ similarBox.style.display="none"; similarBox.innerHTML=""; }
  }
  document.getElementById("stat-avail").textContent=cnt.available;
  document.getElementById("stat-sold").textContent=cnt.sold||0;
  document.getElementById("stat-pend").textContent=cnt.pending||0;
  document.getElementById("d-plat-img").src=s.image;
  document.getElementById("d-plat-img").alt=s.name+" Plat Map";
  renderPlatOverlay(s);
  const galleryWrap=document.getElementById("d-photo-gallery-wrap");
  const galleryGrid=document.getElementById("d-photo-gallery");
  if(galleryWrap&&galleryGrid&&s.photoGallery&&s.photoGallery.length){
    galleryWrap.style.display="block";
    galleryGrid.innerHTML=s.photoGallery.map((src,idx)=>`<img src="${src}" alt="${s.name} aerial photo ${idx+1}" loading="lazy">`).join("");
  }else if(galleryWrap&&galleryGrid){
    galleryWrap.style.display="none";
    galleryGrid.innerHTML="";
  }
  const vw=document.getElementById("d-video-wrap");
  if(s.videoId){vw.style.display="block";document.getElementById("d-video").innerHTML=`<iframe src="https://www.youtube.com/embed/${s.videoId}?muted=1" frameborder="0" allowfullscreen></iframe>`}else vw.style.display="none";
  document.getElementById("d-map").src=(typeof s.lat==="number"&&typeof s.lng==="number")?`https://maps.google.com/maps?q=${s.lat},${s.lng}&z=15&output=embed`:s.mapsEmbed;
  document.getElementById("d-map-link").href=s.mapUrl||(typeof s.lat==="number"&&typeof s.lng==="number"?`https://www.google.com/maps?q=${s.lat},${s.lng}`:s.mapsEmbed);
  renderLotGrid(s);
  renderFAQ(s);
  document.getElementById("calc-price").value=minP<Infinity?minP:"";
  calcPayment();
  const sel=document.getElementById("cf-lot");
  sel.innerHTML=`<option value="">— Select a ${s.unitLabel||"Lot"} —</option>`;
  s.lots.filter(l=>l.status==="available").forEach(l=>{sel.innerHTML+=`<option value="${s.unitLabel||"Lot"} #${l.id}">${s.unitLabel||"Lot"} #${l.id} — ${fmtP(l.price)}</option>`});
    if(isSoldOut){sel.innerHTML+=`<option value="Interest List / Similar Lots">Interest List / Similar Lots</option>`;}
}

function renderLotGrid(s){
  const grid=document.getElementById("d-lot-grid");
  grid.innerHTML="";
  s.lots.forEach(lot=>{
    const btn=document.createElement("button");
    const cls=lot.status==="pending"?"pending":lot.status==="hold"?"hold":lot.status;
    btn.className="lot-btn "+cls;
    btn.id="lot-btn-"+lot.id;
    const priceStr=lot.status==="available"?`<span class="lot-price-tiny">${fmtP(lot.price)}</span>`:(lot.status==="sold"?'<span class="lot-status-tiny">SOLD</span>':(lot.status==="hold"?'<span class="lot-status-tiny">HOLD</span>':'<span class="lot-status-tiny">PEND</span>'));
    btn.innerHTML=`<span class="lot-num">${s.unitLabel?`${s.unitLabel} #${lot.id}`:`#${lot.id}`}</span>${priceStr}`;
    if(lot.status!=="sold"){btn.onclick=()=>openPanel(lot)}else btn.title="This lot has been sold";
    grid.appendChild(btn);
  });
}

function renderFAQ(s){
  document.getElementById("d-faq").innerHTML=(s.faq||[]).map((f,i)=>`<div class="faq-item"><button class="faq-q" onclick="toggleFAQ(${i})"><span>${f.q}</span><span class="faq-icon" id="faq-icon-${i}">▼</span></button><div class="faq-a" id="faq-a-${i}">${f.a}</div></div>`).join("")
}
function toggleFAQ(i){const a=document.getElementById("faq-a-"+i),ic=document.getElementById("faq-icon-"+i),open=a.classList.contains("open");a.classList.toggle("open",!open);ic.classList.toggle("open",!open)}

function openPanel(lot){
  if(activeLotId){document.getElementById("lot-btn-"+activeLotId)?.classList.remove("selected");document.getElementById("plat-lot-"+activeLotId)?.classList.remove("selected");}
  activeLotId=lot.id;
  document.getElementById("lot-btn-"+lot.id)?.classList.add("selected");document.getElementById("plat-lot-"+lot.id)?.classList.add("selected");
  const pill=document.getElementById("p-pill");
  pill.className="status-pill "+(lot.status==="pending"?"pending":lot.status==="hold"?"hold":lot.status==="sold"?"sold":"avail");
  pill.textContent=lot.status==="hold"?"Reserved":lot.status.charAt(0).toUpperCase()+lot.status.slice(1);
  document.getElementById("p-num").textContent=(currentSubdiv?.unitLabel||"Lot")+" #"+lot.id;
  const priceEl=document.getElementById("p-price");
  if(lot.status==="sold"){priceEl.textContent="SOLD";priceEl.className="panel-price sold-price"}
  else{priceEl.textContent=fmtP(lot.price);priceEl.className="panel-price"}
  document.getElementById("p-dims").textContent=lot.dims||"See plat";
  document.getElementById("p-acres").textContent=lot.acres?" "+lot.acres+" ac":"—";
  document.getElementById("p-subdiv").textContent=currentSubdiv?.name||"";
  if(lot.status==="available"){document.getElementById("calc-price").value=lot.price;calcPayment()}
  const acts=document.getElementById("p-actions"),ph="9563833222",phd="(956) 383-3222";
  const subj=encodeURIComponent((currentSubdiv?.name||"")+" – "+(currentSubdiv?.unitLabel||"Lot")+" #"+lot.id);
  const body=encodeURIComponent("Hello, I am interested in "+(currentSubdiv?.unitLabel||"Lot")+" #"+lot.id+" in "+(currentSubdiv?.name||"")+". Please contact me.");
  const waMsg=encodeURIComponent("Hi! I'm interested in "+(currentSubdiv?.unitLabel||"Lot")+" #"+lot.id+" in "+(currentSubdiv?.name||"")+". Can you help?");
  if(lot.status==="available"){acts.innerHTML=`<a href="tel:${ph}" class="btn btn-call">📞 Call ${phd}</a><a href="mailto:CustomerService@PueblodePalmas.com?subject=${subj}&body=${body}" class="btn btn-email">✉️ Email About This Lot</a>`}
  else if(lot.status==="hold"){acts.innerHTML=`<div class="alert-box alert-pend">⚪ Reserved &mdash; call to ask about availability</div><a href="tel:${ph}" class="btn btn-call">📞 Call ${phd}</a>`}
  else if(lot.status==="pending"){acts.innerHTML=`<div class="alert-box alert-pend">⏳ Pending &mdash; call to ask about availability</div><a href="tel:${ph}" class="btn btn-call">📞 Call ${phd}</a>`}
  else{acts.innerHTML=`<div class="alert-box alert-sold">🏡 This lot has been sold</div><a href="https://www.paylease.com/registration/pay_portal/77472037/ACC?vpw=1536&crd=1" class="btn btn-pay" target="_blank">💳 Make a Payment Online</a>`}
  document.getElementById("lot-panel").classList.add("open");
  document.getElementById("overlay").classList.add("on");
}
function closePanel(){
  if(activeLotId){document.getElementById("lot-btn-"+activeLotId)?.classList.remove("selected");document.getElementById("plat-lot-"+activeLotId)?.classList.remove("selected");activeLotId=null}
  document.getElementById("lot-panel").classList.remove("open");
  document.getElementById("overlay").classList.remove("on");
}

function calcPayment(){
  const P=parseFloat(document.getElementById("calc-price").value)||0;
  const down=parseFloat(document.getElementById("calc-down").value)||0;
  const r=parseFloat(document.getElementById("calc-rate").value)||12;
  const y=parseFloat(document.getElementById("calc-term").value)||15;
  const loan=P*(1-down/100),mRate=r/100/12,n=y*12;
  let m=0;if(loan>0&&mRate>0&&n>0)m=loan*mRate*Math.pow(1+mRate,n)/(Math.pow(1+mRate,n)-1);
  document.getElementById("calc-monthly").textContent=m>0?"$"+Math.round(m).toLocaleString()+"/mo":"—";
}

function submitInquiry(){
  const name=document.getElementById("cf-name").value.trim(),phone=document.getElementById("cf-phone").value.trim(),email=document.getElementById("cf-email").value.trim(),lot=document.getElementById("cf-lot").value;
  if(!name||!phone){alert("Please enter your name and phone number.");return}
  const sub=encodeURIComponent("Interest Inquiry: "+(currentSubdiv?.name||"")+" "+lot);
  const bod=encodeURIComponent("Name: "+name+"\nPhone: "+phone+"\nEmail: "+email+"\nProperty: "+(currentSubdiv?.name||"")+"\nLot: "+(lot||"General Inquiry")+"\n\nSent from Pueblo de Palmas website.");
  window.open("mailto:CustomerService@PueblodePalmas.com?subject="+sub+"&body="+bod);
}

